const response = $input.first().json;
const results = response.results || [];
const output = [];

for (const page of results) {
  if (page.object !== 'page') continue;

  // Extract page title
  let title = 'Untitled';
  try {
    const titleProp = Object.values(page.properties || {}).find(p => p.type === 'title');
    if (titleProp && titleProp.title && titleProp.title.length > 0) {
      title = titleProp.title.map(t => t.plain_text).join('');
    }
  } catch (e) {}

  // Classify namespace by title keywords
  const lower = title.toLowerCase();
  let namespace = 'jrih';
  if (lower.includes('axiom')) namespace = 'axiom';
  else if (lower.includes('lumena')) namespace = 'lumena';
  else if (lower.includes('aro')) namespace = 'aro';
  else if (lower.includes('hoj') || lower.includes('heart of juniper')) namespace = 'heart_of_juniper';
  else if (lower.includes('personal') || lower.includes('rose')) namespace = 'personal';
  else if (lower.includes('intel') || lower.includes('research')) namespace = 'intel';
  else if (lower.includes('infra') || lower.includes('ops')) namespace = 'infra';

  // Minimal content: title + page URL for reference
  const content = `Notion Page: ${title}\nURL: ${page.url || ''}\nLast edited: ${page.last_edited_time || ''}`;

  output.push({
    json: {
      content,
      title,
      namespace,
      page_id: page.id,
      page_url: page.url || '',
      last_edited: page.last_edited_time || '',
      tags_json: JSON.stringify(['notion', namespace, 'page']),
      metadata_json: JSON.stringify({
        page_id: page.id,
        page_url: page.url || '',
        last_edited: page.last_edited_time || '',
        ingested_by: 'n8n-notion'
      })
    }
  });
}

return output;
